1	// ABOUTME: Chat panel UI module — tabbed chat panel for ACP agent conversations.
2	// ABOUTME: Manages chat tabs, WebSocket connections, streaming text, and tool call cards.
3	
4	(function () {
5	  "use strict";
6	
7	  // --- Markdown setup ---
8	  marked.setOptions({
9	    highlight: function (code, lang) {
10	      if (lang && hljs.getLanguage(lang)) {
11	        return hljs.highlight(code, { language: lang }).value;
12	      }
13	      return hljs.highlightAuto(code).value;
14	    },
15	    breaks: true,
16	    gfm: true,
17	  });
18	
19	  // --- State ---
20	  var chatTabs = {};
21	  var activeChatTabId = null;
22	  var chatTabIdCounter = 0;
23	
24	  // --- DOM refs ---
25	  var $chatPanel = document.getElementById("chat-panel");
26	  var $chatTabs = document.getElementById("chat-tabs");
27	  var $chatMessages = document.getElementById("chat-messages");
28	  var $chatInput = document.getElementById("chat-input");
29	  var $chatSend = document.getElementById("chat-send");
30	  var $chatStop = document.getElementById("chat-stop");
31	  var $chatCost = document.getElementById("chat-cost");
32	  var $imagePreview = document.getElementById("chat-image-preview");
33	  var $chatEmpty = document.getElementById("chat-empty");
34	
35	  // --- Helpers ---
36	
37	  function escapeHtml(s) {
38	    var div = document.createElement("div");
39	    div.textContent = s;
40	    return div.innerHTML;
41	  }
42	
43	  function renderMarkdown(text) {
44	    return DOMPurify.sanitize(marked.parse(text || ""));
45	  }
46	
47	  function generateChatTabId() {
48	    return "chat-" + (chatTabIdCounter++);
49	  }
50	
51	  function scrollToBottom() {
52	    if (!$chatMessages) return;
53	    $chatMessages.scrollTop = $chatMessages.scrollHeight;
54	  }
55	
56	  // --- Tool call icons by kind ---
57	  var TOOL_ICONS = {
58	    read: "&#128196;",     // page
59	    edit: "&#9998;",       // pencil
60	    execute: "&#9654;",    // play
61	    search: "&#128269;",   // magnifier
62	    "delete": "&#128465;", // trash
63	    think: "&#128161;",    // lightbulb
64	    fetch: "&#127760;",    // globe
65	  };
66	
67	  // --- Empty state ---
68	
69	  function updateEmptyState() {
70	    if (!$chatEmpty) return;
71	    var hasTabs = Object.keys(chatTabs).length > 0;
72	    $chatEmpty.classList.toggle("hidden", hasTabs);
73	    // Hide input bar and header when no tabs
74	    var inputBar = $chatPanel.querySelector(".chat-input-bar");
75	    if (inputBar) inputBar.style.display = hasTabs ? "" : "none";
76	    var header = $chatPanel.querySelector(".chat-panel-header");
77	    if (header) header.style.display = hasTabs ? "" : "none";
78	    var body = $chatPanel.querySelector(".chat-body");
79	    if (body) body.style.display = hasTabs ? "" : "none";
80	  }
81	
82	  // --- Tab Management ---
83	
84	  function renderChatTabs() {
85	    $chatTabs.innerHTML = "";
86	    Object.keys(chatTabs).forEach(function (tabId) {
87	      var tab = chatTabs[tabId];
88	      var el = document.createElement("div");
89	      el.className = "chat-tab" + (tabId === activeChatTabId ? " active" : "") +
90	        (tab.streaming ? " streaming" : "");
91	      el.innerHTML =
92	        '<span class="chat-tab-title">' + escapeHtml(tab.title) + "</span>" +
93	        '<span class="chat-tab-close">&times;</span>';
94	
95	      el.querySelector(".chat-tab-title").addEventListener("click", function () {
96	        switchChatTab(tabId);
97	      });
98	      el.querySelector(".chat-tab-close").addEventListener("click", function (e) {
99	        e.stopPropagation();
100	        closeChatTab(tabId);
101	      });
102	      $chatTabs.appendChild(el);
103	    });
104	  }
105	
106	  function switchChatTab(tabId) {
107	    if (!chatTabs[tabId]) return;
108	    if (activeChatTabId && chatTabs[activeChatTabId]) {
109	      chatTabs[activeChatTabId].container.classList.remove("active");
110	    }
111	    activeChatTabId = tabId;
112	    chatTabs[tabId].container.classList.add("active");
113	    renderChatTabs();
114	    renderTurnSidebar(chatTabs[tabId]);
115	    updateInputState();
116	    renderImagePreview();
117	    scrollToBottom();
118	    $chatInput.focus();
119	  }
120	
121	  function closeChatTab(tabId) {
122	    var tab = chatTabs[tabId];
123	    if (!tab) return;
124	    var closedSessionId = tab.sessionId;
125	    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
126	      tab.ws.close();
127	    }
128	    if (tab.container && tab.container.parentNode) {
129	      tab.container.parentNode.removeChild(tab.container);
130	    }
131	    delete chatTabs[tabId];
132	    if (closedSessionId) {
133	      emitSessionEvent("agent-session-closed", { sessionId: closedSessionId });
134	    }
135	
136	    var remaining = Object.keys(chatTabs);
137	    if (remaining.length > 0) {
138	      switchChatTab(remaining[remaining.length - 1]);
139	    } else {
140	      activeChatTabId = null;
141	    }
142	    renderChatTabs();
143	    updateEmptyState();
144	  }
145	
146	  // --- Chat Tab Creation ---
147	
148	  function createChatTab(title, agent, cwd, existingSessionId, sessionSummary) {
149	    var tabId = generateChatTabId();
150	
151	    var container = document.createElement("div");
152	    container.className = "chat-tab-container";
153	    $chatMessages.appendChild(container);
154	
155	    var tabData = {
156	      id: tabId,
157	      ws: null,
158	      sessionId: null,
159	      agent: agent,
160	      cwd: cwd,
161	      container: container,
162	      title: title,
163	      streaming: false,
164	      messageQueue: [],
165	      currentTextAccum: "",
166	      currentTextEl: null,
167	      thinkingAccum: "",
168	      thinkingEl: null,
169	      renderScheduled: false,
170	      sessionSummary: sessionSummary || null,
171	      userTurns: [],
172	      activeTurnIndex: -1,
173	      pendingImages: [],
174	    };
175	    chatTabs[tabId] = tabData;
176	
177	    // Hide previous active tab
178	    if (activeChatTabId && chatTabs[activeChatTabId]) {
179	      chatTabs[activeChatTabId].container.classList.remove("active");
180	    }
181	    activeChatTabId = tabId;
182	    container.classList.add("active");
183	
184	    renderChatTabs();
185	    renderTurnSidebar(tabData);
186	    updateInputState();
187	    renderImagePreview();
188	    updateEmptyState();
189	    connectWebSocket(tabData, existingSessionId);
190	    $chatInput.focus();
191	
192	    return tabId;
193	  }
194	
195	  // --- WebSocket ---
196	
197	  function connectWebSocket(tabData, sessionId) {
198	    var wsProtocol = location.protocol === "https:" ? "wss:" : "ws:";
199	    var wsUrl = wsProtocol + "//" + location.host + "/ws/chat";
200	    var ws = new WebSocket(wsUrl);
201	    tabData.ws = ws;
202	
203	    ws.onopen = function () {
204	      ws.send(JSON.stringify({
205	        type: "start",
206	        agent: tabData.agent,
207	        cwd: tabData.cwd,
208	        sessionId: sessionId || undefined,
209	      }));
210	    };
211	
212	    ws.onmessage = function (evt) {
213	      try {
214	        var msg = JSON.parse(evt.data);
215	        handleServerMessage(tabData, msg);
216	      } catch (e) {
217	        console.error("Failed to parse chat message:", e);
218	      }
219	    };
220	
221	    ws.onclose = function () {
222	      tabData.streaming = false;
223	      updateInputState();
224	      renderChatTabs();
225	    };
226	
227	    ws.onerror = function () {
228	      appendSystemMessage(tabData, "Connection error");
229	    };
230	  }
231	
232	  // --- Message Routing ---
233	
234	  function handleServerMessage(tabData, msg) {
235	    switch (msg.type) {
236	      case "session_init":
237	        tabData.sessionId = msg.sessionId;
238	        if (msg.agentInfo) {
239	          appendSystemMessage(tabData, msg.agentInfo.title + " connected");
240	        }
241	        if (!msg.historyLoaded && tabData.sessionSummary) {
242	          appendInfoBanner(tabData, "Previous messages not available. " + tabData.sessionSummary);
243	        }
244	        emitSessionEvent("agent-session-started", {
245	          sessionId: msg.sessionId,
246	          agent: tabData.agent,
247	          cwd: tabData.cwd,
248	          title: tabData.title,
249	        });
250	        break;
251	
252	      case "update":
253	        handleUpdate(tabData, msg);
254	        break;
255	
256	      case "turn_complete":
257	        finalizeAssistantMessage(tabData);
258	        collapseCompletedTools(tabData);
259	        tabData.streaming = false;
260	        flushMessageQueue(tabData);
261	        updateInputState();
262	        renderChatTabs();
263	        emitSessionEvent("agent-session-updated", {
264	          sessionId: tabData.sessionId,
265	          streaming: tabData.streaming,
266	        });
267	        break;
268	
269	      case "error":
270	        appendSystemMessage(tabData, "Error: " + (msg.message || "Unknown error"));
271	        tabData.streaming = false;
272	        updateInputState();
273	        renderChatTabs();
274	        break;
275	
276	      case "auth_required":
277	        appendAuthBanner(tabData, msg);
278	        break;
279	
280	      case "session_terminated":
281	        tabData.streaming = false;
282	        tabData.terminated = true;
283	        appendSessionTerminated(tabData);
284	        updateInputState();
285	        renderChatTabs();
286	        break;
287	
288	      case "session_restarted":
289	        tabData.terminated = false;
290	        tabData.sessionId = msg.sessionId || tabData.sessionId;
291	        appendSystemMessage(tabData, "Session resumed");
292	        break;
293	
294	      default:
295	        console.log("Unknown chat message type:", msg.type);
296	    }
297	  }
298	
299	  function handleUpdate(tabData, msg) {
300	    var su = msg.sessionUpdate;
301	    switch (su) {
302	      case "agent_message_chunk":
303	        var text = (msg.content && msg.content.text) || "";
304	        if (text) appendAgentText(tabData, text);
305	        break;
306	
307	      case "agent_thought_chunk":
308	        var thought = (msg.content && msg.content.text) || "";
309	        if (thought) appendThinking(tabData, thought);
310	        break;
311	
312	      case "user_message_chunk":
313	        var userText = (msg.content && msg.content.text) || "";
314	        if (userText) appendUserBubble(tabData, userText);
315	        break;
316	
317	      case "tool_call":
318	        renderToolCall(tabData, msg);
319	        break;
320	
321	      case "tool_call_update":
322	        updateToolCall(tabData, msg);
323	        break;
324	
325	      case "usage_update":
326	        renderUsage(msg);
327	        break;
328	
329	      case "plan":
330	        renderPlan(tabData, msg.entries || []);
331	        break;
332	
333	      default:
334	        break;
335	    }
336	  }
337	
338	  // --- Rendering: User Messages ---
339	
340	  function appendUserBubble(tabData, text, images) {
341	    finalizeAssistantMessage(tabData);
342	
343	    var turnIndex = tabData.userTurns.length;
344	    var bubble = document.createElement("div");
345	    bubble.className = "chat-bubble user";
346	    bubble.setAttribute("data-turn-index", turnIndex);
347	    if (images && images.length) {
348	      var imgStrip = document.createElement("div");
349	      imgStrip.className = "chat-bubble-images";
350	      images.forEach(function (img) {
351	        var el = document.createElement("img");
352	        el.src = "data:" + img.mimeType + ";base64," + img.data;
353	        el.className = "chat-bubble-img";
354	        imgStrip.appendChild(el);
355	      });
356	      bubble.appendChild(imgStrip);
357	    }
358	    if (text) {
359	      var textEl = document.createElement("span");
360	      textEl.textContent = text;
361	      bubble.appendChild(textEl);
362	    }
363	    tabData.container.appendChild(bubble);
364	
365	    tabData.userTurns.push({ index: turnIndex, element: bubble, text: text || "(image)" });
366	    renderTurnSidebar(tabData);
367	    scrollToBottom();
368	  }
369	
370	  // --- Rendering: Agent Text (streaming) ---
371	
372	  function appendAgentText(tabData, text) {
373	    finalizeThinking(tabData);
374	
375	    tabData.currentTextAccum += text;
376	    if (!tabData.currentTextEl) {
377	      var bubble = document.createElement("div");
378	      bubble.className = "chat-bubble assistant";
379	      var content = document.createElement("div");
380	      content.className = "chat-md-content";
381	      bubble.appendChild(content);
382	      tabData.container.appendChild(bubble);
383	      tabData.currentTextEl = content;
384	    }
385	    scheduleRender(tabData);
386	  }
387	
388	  function scheduleRender(tabData) {
389	    if (tabData.renderScheduled) return;
390	    tabData.renderScheduled = true;
391	    requestAnimationFrame(function () {
392	      tabData.renderScheduled = false;
393	      if (tabData.currentTextEl) {
394	        tabData.currentTextEl.innerHTML = renderMarkdown(tabData.currentTextAccum);
395	      }
396	      scrollToBottom();
397	    });
398	  }
399	
400	  function finalizeAssistantMessage(tabData) {
401	    if (tabData.currentTextEl && tabData.currentTextAccum) {
402	      tabData.currentTextEl.innerHTML = renderMarkdown(tabData.currentTextAccum);
403	    }
404	    tabData.currentTextEl = null;
405	    tabData.currentTextAccum = "";
406	    finalizeThinking(tabData);
407	  }
408	
409	  // --- Rendering: Thinking ---
410	
411	  function appendThinking(tabData, text) {
412	    tabData.thinkingAccum += text;
413	    if (!tabData.thinkingEl) {
414	      var block = document.createElement("details");
415	      block.className = "chat-thinking";
416	      block.innerHTML = "<summary>Thinking...</summary><div class='chat-thinking-content'></div>";
417	      tabData.container.appendChild(block);
418	      tabData.thinkingEl = block.querySelector(".chat-thinking-content");
419	    }
420	    tabData.thinkingEl.textContent = tabData.thinkingAccum;
421	    scrollToBottom();
422	  }
423	
424	  function finalizeThinking(tabData) {
425	    tabData.thinkingEl = null;
426	    tabData.thinkingAccum = "";
427	  }
428	
429	  // --- Rendering: Tool Calls ---
430	
431	  function renderToolCall(tabData, tc) {
432	    finalizeAssistantMessage(tabData);
433	
434	    var card = document.createElement("details");
435	    card.className = "chat-tool-card";
436	    card.setAttribute("data-tool-id", tc.toolCallId || "");
437	
438	    var status = tc.status || "pending";
439	    var kind = tc.kind || "other";
440	    var icon = TOOL_ICONS[kind] || "&#128295;";
441	    var title = tc.title || "Tool call";
442	    var locationText = "";
443	    if (tc.locations && tc.locations.length > 0) {
444	      var loc = tc.locations[0];
445	      var path = (loc && loc.path) || "";
446	      locationText = '<span class="chat-tool-path">' + escapeHtml(path.split("/").pop()) + "</span>";
447	    }
448	
449	    card.innerHTML =
450	      '<summary class="chat-tool-header">' +
451	        '<span class="chat-tool-icon">' + icon + "</span>" +
452	        '<span class="chat-tool-title">' + escapeHtml(title) + "</span>" +
453	        locationText +
454	        '<span class="chat-tool-status ' + escapeHtml(status) + '">' + escapeHtml(status) + "</span>" +
455	      "</summary>" +
456	      '<div class="chat-tool-body"></div>';
457	
458	    tabData.container.appendChild(card);
459	    scrollToBottom();
460	  }
461	
462	  function updateToolCall(tabData, update) {
463	    var card = tabData.container.querySelector(
464	      '.chat-tool-card[data-tool-id="' + (update.toolCallId || "") + '"]'
465	    );
466	    if (!card) return;
467	
468	    if (update.status) {
469	      var badge = card.querySelector(".chat-tool-status");
470	      if (badge) {
471	        badge.textContent = update.status;
472	        badge.className = "chat-tool-status " + update.status;
473	      }
474	    }
475	
476	    if (update.content && update.content.length > 0) {
477	      var body = card.querySelector(".chat-tool-body");
478	      if (body) {
479	        update.content.forEach(function (item) {
480	          if (item.type === "diff") {
481	            renderDiff(body, item);
482	          } else if (item.type === "content" && item.content) {
483	            var text = item.content.text || "";
484	            if (text) {
485	              var pre = document.createElement("pre");
486	              pre.className = "chat-tool-output";
487	              pre.textContent = text.length > 2000 ? text.substring(0, 2000) + "\n...(truncated)" : text;
488	              body.appendChild(pre);
489	            }
490	          }
491	        });
492	      }
493	    }
494	    scrollToBottom();
495	  }
496	
497	  function renderDiff(container, diff) {
498	    var el = document.createElement("div");
499	    el.className = "chat-diff";
500	    var header = document.createElement("div");
501	    header.className = "chat-diff-header";
502	    header.textContent = diff.path || "file";
503	    el.appendChild(header);
504	
505	    var pre = document.createElement("pre");
506	    pre.className = "chat-diff-content";
507	    pre.textContent = diff.newText || "";
508	    el.appendChild(pre);
509	    container.appendChild(el);
510	  }
511	
512	  // --- Rendering: Plan ---
513	
514	  function renderPlan(tabData, entries) {
515	    var existing = tabData.container.querySelector(".chat-plan");
516	    if (existing) existing.parentNode.removeChild(existing);
517	
518	    if (!entries.length) return;
519	
520	    var el = document.createElement("div");
521	    el.className = "chat-plan";
522	    el.innerHTML = "<div class='chat-plan-title'>Plan</div>";
523	    var list = document.createElement("ul");
524	    entries.forEach(function (entry) {
525	      var li = document.createElement("li");
526	      var statusIcon = entry.status === "completed" ? "&#10003;" : entry.status === "failed" ? "&#10007;" : "&#9744;";
527	      li.innerHTML = '<span class="chat-plan-icon">' + statusIcon + '</span> ' + escapeHtml(entry.content || "");
528	      li.className = "chat-plan-entry " + (entry.status || "pending");
529	      list.appendChild(li);
530	    });
531	    el.appendChild(list);
532	    tabData.container.appendChild(el);
533	    scrollToBottom();
534	  }
535	
536	  // --- Rendering: Usage ---
537	
538	  function renderUsage(msg) {
539	    if (!$chatCost) return;
540	    var parts = [];
541	
542	    if (msg.cost && msg.cost.amount != null) {
543	      parts.push("$" + msg.cost.amount.toFixed(4));
544	    }
545	
546	    if (msg.used != null && msg.size != null && msg.size > 0) {
547	      var usedK = Math.round(msg.used / 1000);
548	      var sizeK = Math.round(msg.size / 1000);
549	      var pct = Math.round((msg.used / msg.size) * 100);
550	      parts.push(usedK + "K / " + sizeK + "K (" + pct + "%)");
551	    }
552	
553	    if (parts.length > 0) {
554	      $chatCost.textContent = parts.join(" | ");
555	      $chatCost.classList.remove("hidden", "context-warn", "context-critical");
556	      if (msg.used != null && msg.size != null && msg.size > 0) {
557	        var pct = (msg.used / msg.size) * 100;
558	        if (pct >= 90) {
559	          $chatCost.classList.add("context-critical");
560	        } else if (pct >= 75) {
561	          $chatCost.classList.add("context-warn");
562	        }
563	      }
564	    }
565	  }
566	
567	  // --- Turn Navigation Sidebar ---
568	
569	  var $turnSidebar = document.getElementById("chat-turn-sidebar");
570	
571	  function renderTurnSidebar(tabData) {
572	    if (!$turnSidebar) return;
573	    var list = $turnSidebar.querySelector(".turn-list");
574	    if (list) list.innerHTML = "";
575	    var turns = tabData.userTurns;
576	    if (turns.length === 0) {
577	      $turnSidebar.classList.add("hidden");
578	      return;
579	    }
580	
581	    $turnSidebar.classList.remove("hidden");
582	    if (!list) return;
583	
584	    turns.forEach(function (turn) {
585	      var item = document.createElement("div");
586	      item.className = "turn-item" + (turn.index === tabData.activeTurnIndex ? " active" : "");
587	      item.setAttribute("data-turn-index", turn.index);
588	
589	      var label = document.createElement("span");
590	      label.className = "turn-label";
591	      label.textContent = (turn.index + 1);
592	
593	      var preview = document.createElement("span");
594	      preview.className = "turn-preview";
595	      var previewText = turn.text.length > 60 ? turn.text.substring(0, 60) + "..." : turn.text;
596	      preview.textContent = previewText;
597	
598	      item.appendChild(label);
599	      item.appendChild(preview);
600	      item.addEventListener("click", function () {
601	        jumpToTurn(tabData, turn.index);
602	      });
603	      list.appendChild(item);
604	    });
605	
606	    var counter = $turnSidebar.querySelector(".turn-counter");
607	    if (counter) {
608	      var current = tabData.activeTurnIndex >= 0 ? (tabData.activeTurnIndex + 1) : "-";
609	      counter.textContent = current + " / " + turns.length;
610	    }
611	  }
612	
613	  function jumpToTurn(tabData, turnIndex) {
614	    var turns = tabData.userTurns;
615	    if (turnIndex < 0 || turnIndex >= turns.length) return;
616	
617	    tabData.activeTurnIndex = turnIndex;
618	    var el = turns[turnIndex].element;
619	    el.scrollIntoView({ behavior: "smooth", block: "center" });
620	
621	    el.classList.add("turn-highlight");
622	    setTimeout(function () { el.classList.remove("turn-highlight"); }, 1500);
623	
624	    renderTurnSidebar(tabData);
625	  }
626	
627	  function jumpToPreviousTurn(tabData) {
628	    if (!tabData || tabData.userTurns.length === 0) return;
629	    var next = tabData.activeTurnIndex <= 0 ? 0 : tabData.activeTurnIndex - 1;
630	    jumpToTurn(tabData, next);
631	  }
632	
633	  function jumpToNextTurn(tabData) {
634	    if (!tabData || tabData.userTurns.length === 0) return;
635	    var max = tabData.userTurns.length - 1;
636	    var next = tabData.activeTurnIndex >= max ? max : tabData.activeTurnIndex + 1;
637	    jumpToTurn(tabData, next);
638	  }
639	
640	  function toggleTurnSidebar() {
641	    if (!$turnSidebar) return;
642	    $turnSidebar.classList.toggle("collapsed");
643	  }
644	
645	  // --- Tool Collapsing ---
646	
647	  function collapseCompletedTools(tabData) {
648	    var container = tabData.container;
649	    var children = Array.from(container.children);
650	    var i = 0;
651	
652	    while (i < children.length) {
653	      if (isCompletedToolCard(children[i])) {
654	        var runStart = i;
655	        while (i < children.length && isCompletedToolCard(children[i])) {
656	          i++;
657	        }
658	        var runLength = i - runStart;
659	        if (runLength >= 3) {
660	          var details = container.ownerDocument.createElement("details");
661	          details.className = "chat-tool-group";
662	          var summary = container.ownerDocument.createElement("summary");
663	          summary.textContent = runLength + " tool calls completed";
664	          details.appendChild(summary);
665	
666	          container.insertBefore(details, children[runStart]);
667	          for (var j = runStart; j < runStart + runLength; j++) {
668	            details.appendChild(children[j]);
669	          }
670	        }
671	      } else {
672	        i++;
673	      }
674	    }
675	  }
676	
677	  function isCompletedToolCard(el) {
678	    if (!el || !el.classList || !el.classList.contains("chat-tool-card")) return false;
679	    var statusEl = el.querySelector(".chat-tool-status");
680	    return statusEl && statusEl.classList.contains("completed");
681	  }
682	
683	  // --- Rendering: System / Info / Auth ---
684	
685	  function appendSystemMessage(tabData, text) {
686	    var el = document.createElement("div");
687	    el.className = "chat-system-msg";
688	    el.textContent = text;
689	    tabData.container.appendChild(el);
690	    scrollToBottom();
691	  }
692	
693	  function appendInfoBanner(tabData, text) {
694	    var el = document.createElement("div");
695	    el.className = "chat-info-banner";
696	    el.textContent = text;
697	    tabData.container.appendChild(el);
698	    scrollToBottom();
699	  }
700	
701	  function appendSessionTerminated(tabData) {
702	    var el = document.createElement("div");
703	    el.className = "chat-system-msg chat-terminated";
704	    el.textContent = "Session ended \u2014 send a message to resume";
705	    tabData.container.appendChild(el);
706	    scrollToBottom();
707	  }
708	
709	  function appendAuthBanner(tabData, msg) {
710	    var el = document.createElement("div");
711	    el.className = "chat-auth-banner";
712	    el.innerHTML =
713	      '<div class="chat-auth-text">' + escapeHtml(msg.message || "Authentication required") + "</div>" +
714	      '<button class="chat-auth-retry">Retry</button>';
715	    el.querySelector(".chat-auth-retry").addEventListener("click", function () {
716	      if (tabData.ws && tabData.ws.readyState === WebSocket.OPEN) {
717	        tabData.ws.send(JSON.stringify({ type: "retry" }));
718	        el.parentNode.removeChild(el);
719	      }
720	    });
721	    tabData.container.appendChild(el);
722	    scrollToBottom();
723	  }
724	
725	  // --- Input Handling ---
726	
727	  function sendUserMessage() {
728	    if (!activeChatTabId || !chatTabs[activeChatTabId]) return;
729	    var tab = chatTabs[activeChatTabId];
730	
731	    var text = $chatInput.value.trim();
732	    var images = tab.pendingImages.slice();
733	    if (!text && !images.length) return;
734	    $chatInput.value = "";
735	    $chatInput.style.height = "auto";
736	
737	    appendUserBubble(tab, text, images);
738	    tab.pendingImages = [];
739	    renderImagePreview();
740	    updateInputPlaceholder();
741	
742	    var queuedMsg = { type: "user_message", text: text };
743	    if (images.length) {
744	      queuedMsg.images = images.map(function (img) {
745	        return { data: img.data, mimeType: img.mimeType };
746	      });
747	    }
748	
749	    if (tab.streaming) {
750	      if (!tab.messageQueue) tab.messageQueue = [];
751	      tab.messageQueue.push(queuedMsg);
752	      updateInputState();
753	      return;
754	    }
755	
756	    sendToAgent(tab, queuedMsg);
757	  }
758	
759	  function sendToAgent(tab, msg) {
760	    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
761	      tab.ws.send(JSON.stringify(msg));
762	      tab.streaming = true;
763	      updateInputState();
764	      renderChatTabs();
765	      emitSessionEvent("agent-session-updated", {
766	        sessionId: tab.sessionId,
767	        streaming: true,
768	      });
769	    }
770	  }
771	
772	  function flushMessageQueue(tab) {
773	    if (!tab.messageQueue || tab.messageQueue.length === 0) return;
774	    var next = tab.messageQueue.shift();
775	    sendToAgent(tab, next);
776	  }
777	
778	  function cancelAgent() {
779	    if (!activeChatTabId || !chatTabs[activeChatTabId]) return;
780	    var tab = chatTabs[activeChatTabId];
781	    if (!tab.streaming) return;
782	    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
783	      tab.ws.send(JSON.stringify({ type: "cancel" }));
784	    }
785	    tab.messageQueue = [];
786	    tab.streaming = false;
787	    appendSystemMessage(tab, "Cancelled by user");
788	    finalizeAssistantMessage(tab);
789	    updateInputState();
790	    renderChatTabs();
791	  }
792	
793	  function updateInputState() {
794	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
795	    var streaming = tab && tab.streaming;
796	    var queued = tab && tab.messageQueue && tab.messageQueue.length > 0;
797	    $chatInput.disabled = false;
798	    if (streaming) {
799	      $chatSend.classList.add("hidden");
800	      $chatStop.classList.remove("hidden");
801	    } else {
802	      $chatSend.classList.remove("hidden");
803	      $chatStop.classList.add("hidden");
804	    }
805	    if (streaming && queued) {
806	      $chatInput.placeholder = queued + " queued...";
807	    } else if (streaming) {
808	      $chatInput.placeholder = "Agent working... Esc to stop";
809	    } else if (tab && tab.terminated) {
810	      $chatInput.placeholder = "Send a message to resume session...";
811	    } else {
812	      $chatInput.placeholder = "Send a message...";
813	    }
814	  }
815	
816	  // Auto-grow textarea
817	  $chatInput.addEventListener("input", function () {
818	    this.style.height = "auto";
819	    this.style.height = Math.min(this.scrollHeight, 150) + "px";
820	  });
821	
822	  // Enter to send, Shift+Enter for newline, Esc to stop
823	  $chatInput.addEventListener("keydown", function (e) {
824	    if (e.key === "Enter" && !e.shiftKey) {
825	      e.preventDefault();
826	      sendUserMessage();
827	    } else if (e.key === "Escape") {
828	      var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
829	      if (tab && tab.streaming) {
830	        e.preventDefault();
831	        cancelAgent();
832	      }
833	    }
834	  });
835	
836	  $chatStop.addEventListener("click", cancelAgent);
837	  $chatSend.addEventListener("click", sendUserMessage);
838	
839	  // --- Image Paste ---
840	
841	  $chatInput.addEventListener("paste", function (e) {
842	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
843	    if (!tab || tab.streaming) return;
844	
845	    var items = e.clipboardData && e.clipboardData.items;
846	    if (!items) return;
847	
848	    for (var i = 0; i < items.length; i++) {
849	      if (items[i].type.indexOf("image/") === 0) {
850	        e.preventDefault();
851	        var file = items[i].getAsFile();
852	        if (!file) continue;
853	        readImageFile(tab, file);
854	      }
855	    }
856	  });
857	
858	  function readImageFile(tab, file) {
859	    var reader = new FileReader();
860	    reader.onload = function () {
861	      var parts = reader.result.split(",");
862	      var mimeType = file.type || "image/png";
863	      var data = parts[1];
864	      tab.pendingImages.push({ data: data, mimeType: mimeType });
865	      renderImagePreview();
866	      updateInputPlaceholder();
867	    };
868	    reader.readAsDataURL(file);
869	  }
870	
871	  function updateInputPlaceholder() {
872	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
873	    if (!tab || tab.streaming || tab.terminated) return;
874	    var n = tab.pendingImages.length;
875	    if (n > 0) {
876	      $chatInput.placeholder = n + " image" + (n > 1 ? "s" : "") + " attached \u2014 add text or press Enter to send";
877	    } else {
878	      $chatInput.placeholder = "Send a message...";
879	    }
880	  }
881	
882	  function renderImagePreview() {
883	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
884	    $imagePreview.innerHTML = "";
885	    if (!tab || !tab.pendingImages.length) {
886	      $imagePreview.classList.remove("active");
887	      return;
888	    }
889	    $imagePreview.classList.add("active");
890	    tab.pendingImages.forEach(function (img, idx) {
891	      var thumb = document.createElement("div");
892	      thumb.className = "image-preview-thumb";
893	      var imgEl = document.createElement("img");
894	      imgEl.src = "data:" + img.mimeType + ";base64," + img.data;
895	      thumb.appendChild(imgEl);
896	      var removeBtn = document.createElement("button");
897	      removeBtn.className = "image-preview-remove";
898	      removeBtn.textContent = "\u00d7";
899	      removeBtn.setAttribute("data-idx", idx);
900	      removeBtn.addEventListener("click", function () {
901	        tab.pendingImages.splice(idx, 1);
902	        renderImagePreview();
903	        updateInputPlaceholder();
904	      });
905	      thumb.appendChild(removeBtn);
906	      $imagePreview.appendChild(thumb);
907	    });
908	  }
909	
910	  // Turn navigation keyboard shortcuts (Ctrl+Up/Down)
911	  document.addEventListener("keydown", function (e) {
912	    if (!activeChatTabId || !chatTabs[activeChatTabId]) return;
913	    var tab = chatTabs[activeChatTabId];
914	
915	    if (e.ctrlKey && e.key === "ArrowUp") {
916	      e.preventDefault();
917	      jumpToPreviousTurn(tab);
918	    } else if (e.ctrlKey && e.key === "ArrowDown") {
919	      e.preventDefault();
920	      jumpToNextTurn(tab);
921	    } else if (e.ctrlKey && e.key === "t") {
922	      e.preventDefault();
923	      toggleTurnSidebar();
924	    }
925	  });
926	
927	  // Initialize empty state
928	  updateEmptyState();
929	
930	  // --- Custom Events ---
931	
932	  function emitSessionEvent(eventName, detail) {
933	    window.dispatchEvent(new CustomEvent(eventName, { detail: detail }));
934	  }
935	
936	  // --- Public API (called from app.js) ---
937	
938	  window.AgentChat = {
939	    getActiveSessionIds: function () {
940	      var ids = new Set();
941	      Object.keys(chatTabs).forEach(function (tabId) {
942	        var tab = chatTabs[tabId];
943	        if (tab.sessionId) ids.add(tab.sessionId);
944	      });
945	      return ids;
