983	
984	  // Exposed for testing
985	  window._chatInternals = {
986	    handleServerMessage: handleServerMessage,
987	    handleUpdate: handleUpdate,
988	    appendAgentText: appendAgentText,
989	    appendUserBubble: appendUserBubble,
990	    finalizeAssistantMessage: finalizeAssistantMessage,
