describe("local command detection", () => {
  let win, api;

  beforeEach(() => {
    win = createChatEnv();
    api = win._chatInternals;
  });

  it("parses command-name XML into command type", () => {
    const result = api.parseLocalCommand(
      '<command-name>/model</command-name>\n            <command-message>model</command-message>\n            <command-args>default</command-args>'
    );
    assert.deepEqual(result, { type: "command", name: "/model" });
  });

  it("parses local-command-stdout XML into stdout type", () => {
    const result = api.parseLocalCommand(
      "<local-command-stdout>Set model to claude-opus-4-6[1m]</local-command-stdout>"
    );
    assert.deepEqual(result, { type: "stdout", text: "Set model to claude-opus-4-6[1m]" });
  });

  it("parses local-command-caveat as caveat type", () => {
    const result = api.parseLocalCommand(
      '<local-command-caveat>Caveat: The messages below were generated by the user while running local commands.</local-command-caveat>'
    );
    assert.deepEqual(result, { type: "caveat" });
  });

